      historico: [{"versao":1,"texto":"O ensino médio, regular ou supletivo, com formação geral ou educação profissional de nível médio, será implantado nos presídios, em obediência ao preceito constitucional de sua universalização.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.163, de 2015","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: o O ensino ministrado aos presos e presas integrar-se-á ao sistema estadual e municipal de ensino e será mantido, administrativa e financeiramente, com o apoio da União, não só com os recursos destinados à educação, mas pelo sistema estadual de justiça ou administração penitenciária.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.163, de 2015","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: o Os sistemas de ensino oferecerão aos presos e às presas cursos supletivos de educação de jovens e adultos.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.163, de 2015","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§3: o A União, os Estados, os Municípios e o Distrito Federal incluirão em seus programas de educação à distância e de utilização de novas tecnologias de ensino, o atendimento aos presos e às presas.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.163, de 2015","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
