      incisos: [{"id":"lep:art-26-inc-I","numero":"I","texto":"o liberado definitivo, pelo prazo de 1 (um) ano a contar da saída do estabelecimento;","alineas":[]},{"id":"lep:art-26-inc-II","numero":"II","texto":"o liberado condicional, durante o período de prova.","alineas":[]}],
