    {
      tipo: "artigo" as const,
      id: "lep:art-31",
      numero: "31",
      caput: "O condenado à pena privativa de liberdade está obrigado ao trabalho na medida de suas aptidões e capacidade.",
      paragrafos: [{"id":"lep:art-31-púnico","numero":"único","texto":"Para o preso provisório, o trabalho não é obrigatório e só poderá ser executado no interior do estabelecimento.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "lep:art-32",
      numero: "32",
      caput: "Na atribuição do trabalho deverão ser levadas em conta a habilitação, a condição pessoal e as necessidades futuras do preso, bem como as oportunidades oferecidas pelo mercado.",
      paragrafos: [{"id":"lep:art-32-p1","numero":"1","texto":"Deverá ser limitado, tanto quanto possível, o artesanato sem expressão econômica, salvo nas regiões de turismo.","alineas":[]},{"id":"lep:art-32-p2","numero":"2","texto":"Os maiores de 60 (sessenta) anos poderão solicitar ocupação adequada à sua idade.","alineas":[]},{"id":"lep:art-32-p3","numero":"3","texto":"Os doentes ou deficientes físicos somente exercerão atividades apropriadas ao seu estado.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "lep:art-33",
      numero: "33",
      caput: "A jornada normal de trabalho não será inferior a 6 (seis) nem superior a 8 (oito) horas, com descanso nos domingos e feriados.",
      paragrafos: [{"id":"lep:art-33-púnico","numero":"único","texto":"Poderá ser atribuído horário especial de trabalho aos presos designados para os serviços de conservação e manutenção do estabelecimento penal.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "lep:art-34",
      numero: "34",
      caput: "O trabalho poderá ser gerenciado por fundação, ou empresa pública, com autonomia administrativa, e terá por objetivo a formação profissional do condenado.",
      paragrafos: [{"id":"lep:art-34-p1","numero":"1","texto":"o. Nessa hipótese, incumbirá à entidade gerenciadora promover e supervisionar a produção, com critérios e métodos empresariais, encarregar-se de sua comercialização, bem como suportar despesas, inclusive pagamento de remuneração adequada. (Renumerado pela Lei nº 10.792, de 2003)","alineas":[]},{"id":"lep:art-34-p2","numero":"2","texto":"o Os governos federal, estadual e municipal poderão celebrar convênio com a iniciativa privada, para implantação de oficinas de trabalho referentes a setores de apoio dos presídios.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"§2: o Os governos federal, estadual e municipal poderão celebrar convênio com a iniciativa privada, para implantação de oficinas de trabalho referentes a setores de apoio dos presídios.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 10.792, de 2003","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
