      id: "lep:art-66",
      numero: "66",
      caput: "Compete ao Juiz da execução:",
      paragrafos: [],
      incisos: [{"id":"lep:art-66-inc-I","numero":"I","texto":"aplicar aos casos julgados lei posterior que de qualquer modo favorecer o condenado;","alineas":[]},{"id":"lep:art-66-inc-II","numero":"II","texto":"declarar extinta a punibilidade;","alineas":[]},{"id":"lep:art-66-inc-III","numero":"III","texto":"decidir sobre:","alineas":[{"id":"lep:art-66-inc-III-a","numero":"a","texto":"soma ou unificação de penas;"},{"id":"lep:art-66-inc-III-b","numero":"b","texto":"progressão ou regressão nos regimes;"},{"id":"lep:art-66-inc-III-c","numero":"c","texto":"detração e remição da pena;"},{"id":"lep:art-66-inc-III-d","numero":"d","texto":"suspensão condicional da pena;"},{"id":"lep:art-66-inc-III-e","numero":"e","texto":"livramento condicional;"},{"id":"lep:art-66-inc-III-f","numero":"f","texto":"incidentes da execução."}]},{"id":"lep:art-66-inc-IV","numero":"IV","texto":"autorizar saídas temporárias;","alineas":[]},{"id":"lep:art-66-inc-V","numero":"V","texto":"determinar:","alineas":[{"id":"lep:art-66-inc-V-a","numero":"a","texto":"a forma de cumprimento da pena restritiva de direitos e fiscalizar sua execução;"},{"id":"lep:art-66-inc-V-b","numero":"b","texto":"a conversão da pena restritiva de direitos e de multa em privativa de liberdade;"},{"id":"lep:art-66-inc-V-c","numero":"c","texto":"a conversão da pena privativa de liberdade em restritiva de direitos;"},{"id":"lep:art-66-inc-V-d","numero":"d","texto":"a aplicação da medida de segurança, bem como a substituição da pena por medida de segurança;"},{"id":"lep:art-66-inc-V-e","numero":"e","texto":"a revogação da medida de segurança;"},{"id":"lep:art-66-inc-V-f","numero":"f","texto":"a desinternação e o restabelecimento da situação anterior;"},{"id":"lep:art-66-inc-V-g","numero":"g","texto":"o cumprimento de pena ou medida de segurança em outra comarca;"},{"id":"lep:art-66-inc-V-h","numero":"h","texto":"a remoção do condenado na hipótese prevista no § 1º, do artigo 86, desta Lei."},{"id":"lep:art-66-inc-V-i","numero":"i","texto":"(VETADO);"},{"id":"lep:art-66-inc-V-j","numero":"j","texto":"a utilização do equipamento de monitoração eletrônica pelo condenado nas hipóteses legais;"}]},{"id":"lep:art-66-inc-VI","numero":"VI","texto":"zelar pelo correto cumprimento da pena e da medida de segurança;","alineas":[]},{"id":"lep:art-66-inc-VII","numero":"VII","texto":"inspecionar, mensalmente, os estabelecimentos penais, tomando providências para o adequado funcionamento e promovendo, quando for o caso, a apuração de responsabilidade;","alineas":[]},{"id":"lep:art-66-inc-VIII","numero":"VIII","texto":"interditar, no todo ou em parte, estabelecimento penal que estiver funcionando em condições inadequadas ou com infringência aos dispositivos desta Lei;","alineas":[]},{"id":"lep:art-66-inc-IX","numero":"IX","texto":"compor e instalar o Conselho da Comunidade.","alineas":[]},{"id":"lep:art-66-inc-X","numero":"X","texto":"emitir anualmente atestado de pena a cumprir.","alineas":[]}],
      referencias: [],
