      incisos: [{"id":"lep:art-68-inc-I","numero":"I","texto":"fiscalizar a regularidade formal das guias de recolhimento e de internamento;","alineas":[]},{"id":"lep:art-68-inc-II","numero":"II","texto":"requerer:","alineas":[{"id":"lep:art-68-inc-II-a","numero":"a","texto":"todas as providências necessárias ao desenvolvimento do processo executivo;"},{"id":"lep:art-68-inc-II-b","numero":"b","texto":"a instauração dos incidentes de excesso ou desvio de execução;"},{"id":"lep:art-68-inc-II-c","numero":"c","texto":"a aplicação de medida de segurança, bem como a substituição da pena por medida de segurança;"},{"id":"lep:art-68-inc-II-d","numero":"d","texto":"a revogação da medida de segurança;"},{"id":"lep:art-68-inc-II-e","numero":"e","texto":"a conversão de penas, a progressão ou regressão nos regimes e a revogação da suspensão condicional da pena e do livramento condicional;"},{"id":"lep:art-68-inc-II-f","numero":"f","texto":"a internação, a desinternação e o restabelecimento da situação anterior."}]},{"id":"lep:art-68-inc-III","numero":"III","texto":"interpor recursos de decisões proferidas pela autoridade judiciária, durante a execução.","alineas":[]}],
