      numero: "72",
      caput: "São atribuições do Departamento Penitenciário Nacional:",
      paragrafos: [{"id":"lep:art-72-p1","numero":"1","texto":"Incumbem também ao Departamento a coordenação e supervisão dos estabelecimentos penais e de internamento federais.","alineas":[]},{"id":"lep:art-72-p2","numero":"2","texto":"Os resultados obtidos por meio do monitoramento e das avaliações periódicas previstas no inciso VII do caput deste artigo serão utilizados para, em função da efetividade da progressão especial para a ressocialização das mulheres de que trata o § 3º do art. 112 desta Lei, avaliar eventual desnecessidade do regime fechado de cumprimento de pena para essas mulheres nos casos de crimes cometidos sem violência ou grave ameaça.","alineas":[]}],
      incisos: [{"id":"lep:art-72-inc-I","numero":"I","texto":"acompanhar a fiel aplicação das normas de execução penal em todo o Território Nacional;","alineas":[]},{"id":"lep:art-72-inc-II","numero":"II","texto":"inspecionar e fiscalizar periodicamente os estabelecimentos e serviços penais;","alineas":[]},{"id":"lep:art-72-inc-III","numero":"III","texto":"assistir tecnicamente as Unidades Federativas na implementação dos princípios e regras estabelecidos nesta Lei;","alineas":[]},{"id":"lep:art-72-inc-IV","numero":"IV","texto":"colaborar com as Unidades Federativas mediante convênios, na implantação de estabelecimentos e serviços penais;","alineas":[]},{"id":"lep:art-72-inc-V","numero":"V","texto":"colaborar com as Unidades Federativas para a realização de cursos de formação de pessoal penitenciário e de ensino profissionalizante do condenado e do internado.","alineas":[]},{"id":"lep:art-72-inc-VI","numero":"VI","texto":"estabelecer, mediante convênios com as unidades federativas, o cadastro nacional das vagas existentes em estabelecimentos locais destinadas ao cumprimento de penas privativas de liberdade aplicadas pela justiça de outra unidade federativa, em especial para presos sujeitos a regime disciplinar.","alineas":[]},{"id":"lep:art-72-inc-VII","numero":"VII","texto":"acompanhar a execução da pena das mulheres beneficiadas pela progressão especial de que trata o § 3º do art. 112 desta Lei, monitorando sua integração social e a ocorrência de reincidência, específica ou não, mediante a realização de avaliações periódicas e de estatísticas criminais.","alineas":[]}],
      referencias: [],
      historico: [{"versao":1,"texto":"Inc. VI: estabelecer, mediante convênios com as unidades federativas, o cadastro nacional das vagas existentes em estabelecimentos locais destinadas ao cumprimento de penas privativas de liberdade aplicadas pela justiça de outra unidade federativa, em especial para presos sujeitos a regime disciplinar.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 10.792, de 2003","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. VII: acompanhar a execução da pena das mulheres beneficiadas pela progressão especial de que trata o § 3º do art. 112 desta Lei, monitorando sua integração social e a ocorrência de reincidência, específica ou não, mediante a realização de avaliações periódicas e de estatísticas criminais.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.769, de 2018","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§1: Incumbem também ao Departamento a coordenação e supervisão dos estabelecimentos penais e de internamento federais.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 13.769, de 2018","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§2: Os resultados obtidos por meio do monitoramento e das avaliações periódicas previstas no inciso VII do caput deste artigo serão utilizados para, em função da efetividade da progressão especial para a ressocialização das mulheres de que trata o § 3º do art. 112 desta Lei, avaliar eventual desnecessidade do regime fechado de cumprimento de pena para essas mulheres nos casos de crimes cometidos sem violência ou grave ameaça.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.769, de 2018","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
