      paragrafos: [],
      incisos: [{"id":"lep:art-117-inc-I","numero":"I","texto":"condenado maior de 70 (setenta) anos;","alineas":[]},{"id":"lep:art-117-inc-II","numero":"II","texto":"condenado acometido de doença grave;","alineas":[]},{"id":"lep:art-117-inc-III","numero":"III","texto":"condenada com filho menor ou deficiente físico ou mental;","alineas":[]},{"id":"lep:art-117-inc-IV","numero":"IV","texto":"condenada gestante.","alineas":[]}],
