      id: "lep:art-152",
      numero: "152",
      caput: "Poderão ser ministrados ao condenado, durante o tempo de permanência, cursos e palestras, ou atribuídas atividades educativas.",
      paragrafos: [{"id":"lep:art-152-púnico","numero":"único","texto":"Nos casos de violência doméstica e familiar contra a criança, o adolescente e a mulher e de tratamento cruel ou degradante, ou de uso de formas violentas de educação, correção ou disciplina contra a criança e o adolescente, o juiz poderá determinar o comparecimento obrigatório do agressor a programas de recuperação e reeducação.  Vigência","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"§único: Nos casos de violência doméstica e familiar contra a criança, o adolescente e a mulher e de tratamento cruel ou degradante, ou de uso de formas violentas de educação, correção ou disciplina contra a criança e o adolescente, o juiz poderá determinar o comparecimento obrigatório do agressor a programas de recuperação e reeducação.  Vigência","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 14.344, de 2022","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
